import 'package:uni_links/uni_links.dart';
import 'package:flutter/material.dart';

class DeepLinkHandler {
  static Future<void> handleDeepLink(BuildContext context) async {
    final rawDeepLink = await getInitialLink();
    if (rawDeepLink != null) {
      final uri = Uri.parse(rawDeepLink);
      String path = uri.path;
      List<String> pathSegments = path.split('/');

      switch (pathSegments[1]) {
        case 'profile':
          if (pathSegments.length >= 3) {
            Navigator.pushNamed(context, '/Profile', arguments: pathSegments[2]);
          }
          break;
        case 'payment':
          if (pathSegments.length >= 3 && pathSegments[2] == 'confirm') {
            Navigator.pushNamed(context, '/PaymentConfirm');
          }
          break;
        default:
          // Handle other routes or redirect to the home screen
      }
    }
  }
}